from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH664_gorm_7668'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH664_gorm_7668'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('being', 'being' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH664_gorm_7668',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'go-gorm/gorm',
                "pr_number": 7668,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/go-gorm/gorm/pull/7668",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'internal/lru/lru.go': 'package lru\n\n// golang -lru\n// https://github.com/hashicorp/golang-lru\nimport (\n\t"sync"\n\t"time"\n)\n\n// EvictCallback is used to get a callback when a cache entry is evicted\ntype EvictCallback[K comparable, V any] func(key K, value V)\n\n// LRU implements a thread-safe LRU with expirable entries.\ntype LRU[K comparable, V any] struct {\n\tsize      int\n\tevictList *LruList[K, V]\n\titems     map[K]*Entry[K, V]\n\tonEvict   EvictCallback[K, V]\n\n\t// expirable options\n\tmu   sync.Mutex\n\tttl  time.Duration\n\tdone chan struct{}\n\n\t// buckets for expiration\n\tbuckets []bucket[K, V]\n\t// uint8 because it\'s number between 0 and numBuckets\n\tnextCleanupBucket uint8\n}\n\n// bucket is a container for holding entries to be expired\ntype bucket[K comparable, V any] struct {\n\tentries     map[K]*Entry[K, V]\n\tnewestEntry time.Time\n}\n\n// noEvictionTTL - very long ttl to prevent eviction\nconst noEvictionTTL = time.Hour * 24 * 365 * 10\n\n// because of uint8 usage for nextCleanupBucket, should not exceed 256.\n// casting it as uint8 explicitly requires type conversions in multiple places\nconst numBuckets = 100\n\n// NewLRU returns a new thread-safe cache with expirable entries.\n//\n// Size parameter set to 0 makes cache of unlimited size, e.g. turns LRU mechanism off.\n//\n// Providing 0 TTL turns expiring off.\n//\n// Delete expired entries every 1/100th of ttl value. Goroutine which deletes expired entries runs indefinitely.\nfunc NewLRU[K comparable, V any](size int, onEvict EvictCallback[K, V], ttl time.Duration) *LRU[K, V] {\n\tif size < 0 {\n\t\tsize = 0\n\t}\n\tif ttl <= 0 {\n\t\tttl = noEvictionTTL\n\t}\n\n\tres := LRU[K, V]{\n\t\tttl:       ttl,\n\t\tsize:      size,\n\t\tevictList: NewList[K, V](),\n\t\titems:     make(map[K]*Entry[K, V]),\n\t\tonEvict:   onEvict,\n\t\tdone:      make(chan struct{}),\n\t}\n\n\t// initialize the buckets\n\tres.buckets = make([]bucket[K, V], numBuckets)\n\tfor i := 0; i < numBuckets; i++ {\n\t\tres.buckets[i] = bucket[K, V]{entries: make(map[K]*Entry[K, V])}\n\t}\n\n\t// enable deleteExpired() running in separate goroutine for cache with non-zero TTL\n\t//\n\t// Important: done channel is never closed, so deleteExpired() goroutine will never exit,\n\t// it\'s decided to add functionality to close it in the version later than v2.\n\tif res.ttl != noEvictionTTL {\n\t\tgo func(done <-chan struct{}) {\n\t\t\tticker := time.NewTicker(res.ttl / numBuckets)\n\t\t\tdefer ticker.Stop()\n\t\t\tfor {\n\t\t\t\tselect {\n\t\t\t\tcase <-done:\n\t\t\t\t\treturn\n\t\t\t\tcase <-ticker.C:\n\t\t\t\t\tres.deleteExpired()\n\t\t\t\t}\n\t\t\t}\n\t\t}(res.done)\n\t}\n\treturn &res\n}\n\n// Purge clears the cache completely.\n// onEvict is called for each evicted key.\nfunc (c *LRU[K, V]) Purge() {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tfor k, v := range c.items {\n\t\tif c.onEvict != nil {\n\t\t\tc.onEvict(k, v.Value)\n\t\t}\n\t\tdelete(c.items, k)\n\t}\n\tfor _, b := range c.buckets {\n\t\tfor _, ent := range b.entries {\n\t\t\tdelete(b.entries, ent.Key)\n\t\t}\n\t}\n\tc.evictList.Init()\n}\n\n// Add adds a value to the cache. Returns true if an eviction occurred.\n// Returns false if there was no eviction: the item was already in the cache,\n// or the size was not exceeded.\nfunc (c *LRU[K, V]) Add(key K, value V) (evicted bool) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tnow := time.Now()\n\n\t// Check for existing item\n\tif ent, ok := c.items[key]; ok {\n\t\tc.evictList.MoveToFront(ent)\n\t\tc.removeFromBucket(ent) // remove the entry from its current bucket as expiresAt is renewed\n\t\tent.Value = value\n\t\tent.ExpiresAt = now.Add(c.ttl)\n\t\tc.addToBucket(ent)\n\t\treturn false\n\t}\n\n\t// Add new item\n\tent := c.evictList.PushFrontExpirable(key, value, now.Add(c.ttl))\n\tc.items[key] = ent\n\tc.addToBucket(ent) // adds the entry to the appropriate bucket and sets entry.expireBucket\n\n\tevict := c.size > 0 && c.evictList.Length() > c.size\n\t// Verify size not exceeded\n\tif evict {\n\t\tc.removeOldest()\n\t}\n\treturn evict\n}\n\n// Get looks up a key\'s value from the cache.\nfunc (c *LRU[K, V]) Get(key K) (value V, ok bool) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tvar ent *Entry[K, V]\n\tif ent, ok = c.items[key]; ok {\n\t\t// Expired item check\n\t\tif time.Now().After(ent.ExpiresAt) {\n\t\t\treturn value, false\n\t\t}\n\t\tc.evictList.MoveToFront(ent)\n\t\treturn ent.Value, true\n\t}\n\treturn\n}\n\n// Contains checks if a key is in the cache, without updating the recent-ness\n// or deleting it for being stale.\nfunc (c *LRU[K, V]) Contains(key K) (ok bool) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\t_, ok = c.items[key]\n\treturn ok\n}\n\n// Peek returns the key value (or undefined if not found) without updating\n// the "recently used"-ness of the key.\nfunc (c *LRU[K, V]) Peek(key K) (value V, ok bool) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tvar ent *Entry[K, V]\n\tif ent, ok = c.items[key]; ok {\n\t\t// Expired item check\n\t\tif time.Now().After(ent.ExpiresAt) {\n\t\t\treturn value, false\n\t\t}\n\t\treturn ent.Value, true\n\t}\n\treturn\n}\n\n// Remove removes the provided key from the cache, returning if the\n// key was contained.\nfunc (c *LRU[K, V]) Remove(key K) bool {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tif ent, ok := c.items[key]; ok {\n\t\tc.removeElement(ent)\n\t\treturn true\n\t}\n\treturn false\n}\n\n// RemoveOldest removes the oldest item from the cache.\nfunc (c *LRU[K, V]) RemoveOldest() (key K, value V, ok bool) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tif ent := c.evictList.Back(); ent != nil {\n\t\tc.removeElement(ent)\n\t\treturn ent.Key, ent.Value, true\n\t}\n\treturn\n}\n\n// GetOldest returns the oldest entry\nfunc (c *LRU[K, V]) GetOldest() (key K, value V, ok bool) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tif ent := c.evictList.Back(); ent != nil {\n\t\treturn ent.Key, ent.Value, true\n\t}\n\treturn\n}\n\nfunc (c *LRU[K, V]) KeyValues() map[K]V {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tmaps := make(map[K]V)\n\tnow := time.Now()\n\tfor ent := c.evictList.Back(); ent != nil; ent = ent.PrevEntry() {\n\t\tif now.After(ent.ExpiresAt) {\n\t\t\tcontinue\n\t\t}\n\t\tmaps[ent.Key] = ent.Value\n\t\t// keys = append(keys, ent.Key)\n\t}\n\treturn maps\n}\n\n// Keys returns a slice of the keys in the cache, from oldest to newest.\n// Expired entries are filtered out.\nfunc (c *LRU[K, V]) Keys() []K {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tkeys := make([]K, 0, len(c.items))\n\tnow := time.Now()\n\tfor ent := c.evictList.Back(); ent != nil; ent = ent.PrevEntry() {\n\t\tif now.After(ent.ExpiresAt) {\n\t\t\tcontinue\n\t\t}\n\t\tkeys = append(keys, ent.Key)\n\t}\n\treturn keys\n}\n\n// Values returns a slice of the values in the cache, from oldest to newest.\n// Expired entries are filtered out.\nfunc (c *LRU[K, V]) Values() []V {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tvalues := make([]V, 0, len(c.items))\n\tnow := time.Now()\n\tfor ent := c.evictList.Back(); ent != nil; ent = ent.PrevEntry() {\n\t\tif now.After(ent.ExpiresAt) {\n\t\t\tcontinue\n\t\t}\n\t\tvalues = append(values, ent.Value)\n\t}\n\treturn values\n}\n\n// Len returns the number of items in the cache.\nfunc (c *LRU[K, V]) Len() int {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\treturn c.evictList.Length()\n}\n\n// Resize changes the cache size. Size of 0 means unlimited.\nfunc (c *LRU[K, V]) Resize(size int) (evicted int) {\n\tc.mu.Lock()\n\tdefer c.mu.Unlock()\n\tif size <= 0 {\n\t\tc.size = 0\n\t\treturn 0\n\t}\n\tdiff := c.evictList.Length() - size\n\tif diff < 0 {\n\t\tdiff = 0\n\t}\n\tfor i := 0; i < diff; i++ {\n\t\tc.removeOldest()\n\t}\n\tc.size = size\n\treturn diff\n}\n\n// Close destroys cleanup goroutine. To clean up the cache, run Purge() before Close().\n// func (c *LRU[K, V]) Close() {\n//\tc.mu.Lock()\n//\tdefer c.mu.Unlock()\n//\tselect {\n//\tcase <-c.done:\n//\t\treturn\n//\tdefault:\n//\t}\n//\tclose(c.done)\n// }\n\n// removeOldest removes the oldest item from the cache. Has to be called with lock!\nfunc (c *LRU[K, V]) removeOldest() {\n\tif ent := c.evictList.Back(); ent != nil {\n\t\tc.removeElement(ent)\n\t}\n}\n\n// removeElement is used to remove a given list element from the cache. Has to be called with lock!\nfunc (c *LRU[K, V]) removeElement(e *Entry[K, V]) {\n\tc.evictList.Remove(e)\n\tdelete(c.items, e.Key)\n\tc.removeFromBucket(e)\n\tif c.onEvict != nil {\n\t\tc.onEvict(e.Key, e.Value)\n\t}\n}\n\n// deleteExpired deletes expired records from the oldest bucket, waiting for the newest entry\n// in it to expire first.\nfunc (c *LRU[K, V]) deleteExpired() {\n\tc.mu.Lock()\n\tbucketIdx := c.nextCleanupBucket\n\ttimeToExpire := time.Until(c.buckets[bucketIdx].newestEntry)\n\t// wait for newest entry to expire before cleanup without holding lock\n\tif timeToExpire > 0 {\n\t\tc.mu.Unlock()\n\t\ttime.Sleep(timeToExpire)\n\t\tc.mu.Lock()\n\t}\n\tfor _, ent := range c.buckets[bucketIdx].entries {\n\t\tc.removeElement(ent)\n\t}\n\tc.nextCleanupBucket = (c.nextCleanupBucket + 1) % numBuckets\n\tc.mu.Unlock()\n}\n\n// addToBucket adds entry to expire bucket so that it will be cleaned up when the time comes. Has to be called with lock!\nfunc (c *LRU[K, V]) addToBucket(e *Entry[K, V]) {\n\tbucketID := (numBuckets + c.nextCleanupBucket - 1) % numBuckets\n\te.ExpireBucket = bucketID\n\tc.buckets[bucketID].entries[e.Key] = e\n\tif c.buckets[bucketID].newestEntry.Before(e.ExpiresAt) {\n\t\tc.buckets[bucketID].newestEntry = e.ExpiresAt\n\t}\n}\n\n// removeFromBucket removes the entry from its corresponding bucket. Has to be called with lock!\nfunc (c *LRU[K, V]) removeFromBucket(e *Entry[K, V]) {\n\tdelete(c.buckets[e.ExpireBucket].entries, e.Key)\n}\n\n// Cap returns the capacity of the cache\nfunc (c *LRU[K, V]) Cap() int {\n\treturn c.size\n}\n\n// Entry is an LRU Entry\ntype Entry[K comparable, V any] struct {\n\t// Next and previous pointers in the doubly-linked list of elements.\n\t// To simplify the implementation, internally a list l is implemented\n\t// as a ring, such that &l.root is both the next element of the last\n\t// list element (l.Back()) and the previous element of the first list\n\t// element (l.Front()).\n\tnext, prev *Entry[K, V]\n\n\t// The list to which this element belongs.\n\tlist *LruList[K, V]\n\n\t// The LRU Key of this element.\n\tKey K\n\n\t// The Value stored with this element.\n\tValue V\n\n\t// The time this element would be cleaned up, optional\n\tExpiresAt time.Time\n\n\t// The expiry bucket item was put in, optional\n\tExpireBucket uint8\n}\n\n// PrevEntry returns the previous list element or nil.\nfunc (e *Entry[K, V]) PrevEntry() *Entry[K, V] {\n\tif p := e.prev; e.list != nil && p != &e.list.root {\n\t\treturn p\n\t}\n\treturn nil\n}\n\n// LruList represents a doubly linked list.\n// The zero Value for LruList is an empty list ready to use.\ntype LruList[K comparable, V any] struct {\n\troot Entry[K, V] // sentinel list element, only &root, root.prev, and root.next are used\n\tlen  int         // current list Length excluding (this) sentinel element\n}\n\n// Init initializes or clears list l.\nfunc (l *LruList[K, V]) Init() *LruList[K, V] {\n\tl.root.next = &l.root\n\tl.root.prev = &l.root\n\tl.len = 0\n\treturn l\n}\n\n// NewList returns an initialized list.\nfunc NewList[K comparable, V any]() *LruList[K, V] { return new(LruList[K, V]).Init() }\n\n// Length returns the number of elements of list l.\n// The complexity is O(1).\nfunc (l *LruList[K, V]) Length() int { return l.len }\n\n// Back returns the last element of list l or nil if the list is empty.\nfunc (l *LruList[K, V]) Back() *Entry[K, V] {\n\tif l.len == 0 {\n\t\treturn nil\n\t}\n\treturn l.root.prev\n}\n\n// lazyInit lazily initializes a zero List Value.\nfunc (l *LruList[K, V]) lazyInit() {\n\tif l.root.next == nil {\n\t\tl.Init()\n\t}\n}\n\n// insert inserts e after at, increments l.len, and returns e.\nfunc (l *LruList[K, V]) insert(e, at *Entry[K, V]) *Entry[K, V] {\n\te.prev = at\n\te.next = at.next\n\te.prev.next = e\n\te.next.prev = e\n\te.list = l\n\tl.len++\n\treturn e\n}\n\n// insertValue is a convenience wrapper for insert(&Entry{Value: v, ExpiresAt: ExpiresAt}, at).\nfunc (l *LruList[K, V]) insertValue(k K, v V, expiresAt time.Time, at *Entry[K, V]) *Entry[K, V] {\n\treturn l.insert(&Entry[K, V]{Value: v, Key: k, ExpiresAt: expiresAt}, at)\n}\n\n// Remove removes e from its list, decrements l.len\nfunc (l *LruList[K, V]) Remove(e *Entry[K, V]) V {\n\te.prev.next = e.next\n\te.next.prev = e.prev\n\te.next = nil // avoid memory leaks\n\te.prev = nil // avoid memory leaks\n\te.list = nil\n\tl.len--\n\n\treturn e.Value\n}\n\n// move moves e to next to at.\nfunc (l *LruList[K, V]) move(e, at *Entry[K, V]) {\n\tif e == at {\n\t\treturn\n\t}\n\te.prev.next = e.next\n\te.next.prev = e.prev\n\n\te.prev = at\n\te.next = at.next\n\te.prev.next = e\n\te.next.prev = e\n}\n\n// PushFront inserts a new element e with value v at the front of list l and returns e.\nfunc (l *LruList[K, V]) PushFront(k K, v V) *Entry[K, V] {\n\tl.lazyInit()\n\treturn l.insertValue(k, v, time.Time{}, &l.root)\n}\n\n// PushFrontExpirable inserts a new expirable element e with Value v at the front of list l and returns e.\nfunc (l *LruList[K, V]) PushFrontExpirable(k K, v V, expiresAt time.Time) *Entry[K, V] {\n\tl.lazyInit()\n\treturn l.insertValue(k, v, expiresAt, &l.root)\n}\n\n// MoveToFront moves element e to the front of list l.\n// If e is not an element of l, the list is not modified.\n// The element must not be nil.\nfunc (l *LruList[K, V]) MoveToFront(e *Entry[K, V]) {\n\tif e.list != l || l.root.next == e {\n\t\treturn\n\t}\n\t// see comment in List.Remove about initialization of l\n\tl.move(e, &l.root)\n}\n',
        }
